```typescript
// throttler-exception.filter.ts
import { ExceptionFilter, Catch, ArgumentsHost, HttpException, HttpStatus } from '@nestjs/common';
import { ThrottlerException } from '@nestjs/throttler';
import { Response } from 'express';

@Catch(ThrottlerException)
export class ThrottlerExceptionFilter implements ExceptionFilter {
  catch(exception: ThrottlerException, host: ArgumentsHost) {
    const ctx = host.switchToHttp();
    const response = ctx.getResponse<Response>();
    const request = ctx.getRequest();

    // Récupérer les headers de throttling (si présents)
    const retryAfter = response.getHeader('Retry-After') || 60;
    const limit = response.getHeader('X-RateLimit-Limit') || 10;
    const remaining = response.getHeader('X-RateLimit-Remaining') || 0;

    response.status(HttpStatus.TOO_MANY_REQUESTS).json({
      statusCode: HttpStatus.TOO_MANY_REQUESTS,
      message: 'Trop de requêtes. Veuillez réessayer plus tard.',
      error: 'Too Many Requests',
      timestamp: new Date().toISOString(),
      path: request.url,
      retryAfter: retryAfter,
      rateLimit: {
        limit: limit,
        remaining: remaining,
        resetTime: new Date(Date.now() + retryAfter * 1000).toISOString(),
      },
    });
  }
}
```

**Application :**
```typescript
// main.ts
app.useGlobalFilters(new ThrottlerExceptionFilter());
```

